        ORB_RELATED_EXPLOITS_I_HAVE_NO_FURTHER_BUSINESS                                  = 7382,  -- Orb-related exploits: I have no further business with you. ails of Woe. ([Unfinished/Conquered/With Honors]) he Worm's Turn. ([Unfinished/Conquered/With Honors]) teamed Sprouts. ([Unfinished/Conquered/With Honors]) actory Rejects. ([Unfinished/Conquered/With Honors]) ismemberment Brigade. ([Unfinished/Conquered/With Honors]) rimshell Shocktroopers. ([Unfinished/Conquered/With Honors]) ivine Punishers. ([Unfinished/Conquered/With Honors]) emolition Squad. ([Unfinished/Conquered/With Honors]) rothers D'Aurphe. ([Unfinished/Conquered/With Honors]) egion XI Comitatensis. ([Unfinished/Conquered/With Honors]) ungle Boogymen. ([Unfinished/Conquered/With Honors]) mphibian Assault. ([Unfinished/Conquered/With Honors]) indred Spirits. ([Unfinished/Conquered/With Honors])
        I_SEE_I_SEE_I_SEE_I_WONDER                                                       = 7383,  -- I see, I see, I see... [Supply's drowning out any demand./If that's the case, then the status quo's probably good to go!/Amazing! You've been smiting everything left and right!] (I wonder how this'll impact my kickbacks.)
        YOU_WILL_NEED_TO_TRAVEL_TO_THE_OUTLANDS                                          = 7384,  -- You will need % to travel to the Outlands by air. You may apply for one at the designated counter.
        THIS_IS_THE_COUNTER_FOR_THE_AIR_ROUTE                                            = 7385,  -- This is the counter for the air route to the Outlands. Our airships connect Jeuno with the southeastern island of Elshimo.
        THIS_IS_THE_COUNTER_FOR_THE_OUTLANDS_AIR                                         = 7386,  -- This is the counter for the Outlands air route. How may I be of assistance today?
        WHAT_IS_YOUR_BUSINESS_HERE_JUST_PASSING_BY                                       = 7387,  -- What is your business here? Just passing by. I want % issued. Tell me about the adventurers' deal.
        YES_WITH_YOU_CAN_TRAVEL_FREELY_BETWEEN_JEUNO                                     = 7388,  -- Yes, with % you can travel freely between Jeuno and Kazham. The price is a mere # gil, and there is no expiration date.
        IF_YOU_CANNOT_AFFORD_OUR_ALREADY_LOW_PRICE                                       = 7389,  -- If you cannot afford our already low price, we are offering, for a limited time, the adventurers' deal. Would you like to hear more on this offer?
        LISTEN_TO_THE_EXPLANATION_YES_NO_BUY                                             = 7390,  -- Listen to the explanation? Yes. No. Buy %.
        YES_THE_ADVENTURERS_DEAL_ALL_YOU_HAVE_TO                                         = 7391,  -- Yes, the adventurers' deal. All you have to do is find these three keys: %, %, and %.
        THE_ADVENTURERS_DEAL_CONSISTS_OF_FINDING_THE_FOLLOWING                           = 7392,  -- The adventurers' deal consists of finding the following three keys: %, %, and %.
        ONCE_YOU_HAVE_GATHERED_THEM_ALL_GIVE_THEM                                        = 7393,  -- Once you have gathered them all, give them to me and I will check to see if they are authentic.
        AND_YES_THEY_SEEM_TO_BE_AUTHENTIC                                                = 7394,  -- %...%...and %. Yes, they seem to be authentic.
        I_HAVE_ISSUED_UNDER_THE_NAME_OF_IT                                               = 7395,  -- I have issued % under the name of %. It has been approved for immediate use.
        I_AM_SORRY_BUT_THIS_IS_NOT_ONE                                                   = 7396,  -- I am sorry, but this is not one of the items in the deal.
        YOU_MUST_BRING_AND                                                               = 7397,  -- You must bring %, %, and %.
        YES_SIR_MA_AM_IF_YOU_NEED_ANY                                                    = 7398,  -- Yes sir/ma'am]. If you need any information on the air routes to the Outlands, feel free to inquire at any time.
        WE_HOPE_YOU_ENJOY_FLYING_WITH_US                                                 = 7399,  -- We hope you enjoy flying with us!
        I_AM_SORRY_BUT_YOU_DO_NOT_HAVE                                                   = 7400,  -- I am sorry, but you do not have enough gil.
        BUY_NOT_TODAY_YES                                                                = 7401,  -- Buy %? Not today. Yes.
        I_M_SORRY_THERE_SON_MISS_BUT_I                                                   = 7402,  -- I'm sorry there, son/miss], but I can only allow one exchange a week per adventurer. Come back again later.
        THIS_IS_THE_DEPARTURE_GATE_FOR_AIRSHIP_PASSENGERS                                = 7403,  -- This is the departure gate for airship passengers. If you have any questions, please inquire with Guddal.
        DELIVERING_GOODS_TO_RESIDENCES_EVERYWHERE                                        = 7404,  -- Delivering goods to residences everywhere!
        GOOD_LUCK_I_WILL_BESTOW_UPON_YOU_YOUR                                            = 7405,  -- Good luck, [citizen/comrade]. I will bestow upon you your nation's Signet.
        I_CANNOT_HELP_YOU_YOU_SHOULD_GO_FIND                                             = 7406,  -- I cannot help you. You should go find a guard from your own country.
        I_CANNOT_ACCEPT_CRYSTALS_FROM_SOMEONE_WHOSE_RANK                                 = 7407,  -- I cannot accept crystals from someone whose rank is still 1. I advise you to either keep them until your reach rank 2, or to use them in craftwork.
        SINCE_WE_ARE_ALLIED_WITH_SAN_D_ORIA                                              = 7408,  -- Since we are allied with San d'Oria...
        SINCE_WE_ARE_ALLIED_WITH_BASTOK                                                  = 7409,  -- Since we are allied with Bastok...
        SINCE_WE_ARE_ALLIED_WITH_WINDURST                                                = 7410,  -- Since we are allied with Windurst...
        I_AM_SORRY_I_AM_TOO_BUSY_WITH                                                    = 7411,  -- I am sorry. I am too busy with other matters to be speaking with you.
        AH_YOU_HAVE_BROUGHT_US_SUPPLIES_THESE_WILL                                       = 7412,  -- Ah, you have brought us supplies. These will help us indeed. I thank you.
        HMM_THESE_SUPPLIES_YOU_HAVE_BROUGHT_US_ARE                                       = 7413,  -- Hmm... These supplies you have brought us are too old to be of any use. We will dispose of them promptly. I do commend you for your effort. May you succeed next time.
        YOU_VE_EARNED_CONQUEST_POINTS                                                    = 7414,  -- You've earned conquest points!
        YOU_VE_RECEIVED_YOUR_NATION_S_SIGNET_YOU                                         = 7415,  -- You've received your nation's Signet. You are now taking part in your nation's conquest campaign!
        I_AM_A_TEMPLE_KNIGHT_I_AM_ONE                                                    = 7416,  -- I am , a Temple Knight. I am one of the guards charged with overseeing San d'Oria's conquest campaign.
        I_AM_AN_IRON_MUSKETEER_I_AM_ONE                                                  = 7417,  -- I am , an Iron Musketeer. I am one of the guards charged with overseeing Bastok's conquest campaign.
        I_AM_A_WAR_WARLOCK_I_AM_ONE                                                      = 7418,  -- I am , a War Warlock. I am one of the guards charged with overseeing Windurst's conquest campaign.
        WHAT_IS_YOUR_BUSINESS_WOULD_YOU_CAST_SIGNET                                      = 7419,  -- What is your business? Would you cast Signet on me? I want to spend my conquest points. [I want to join the Expeditionary Force./Teleport me to the E.F. area.] I want to quit the E.F./change my E.F. I want to go on a supplies quest. I have some questions... Nothing, sorry to bother you.
        WHAT_DO_YOU_WISH_TO_KNOW_ABOUT_NOTHING                                           = 7420,  -- What do you wish to know about? Nothing. Conquests. Conquest results. Donating crystals. Conquest points. The effects of controlling regions. Regions controlled by other nations. Regions under beastman control.
        ALL_THREE_NATIONS_ARE_STRIVING_DAILY_TO_PUT                                      = 7421,  -- All three nations are striving daily to put more regions under their control. This is what we call conquests. You can take part in it and serve your country by defeating enemies while you have Signet cast on you.
        EACH_REGION_COMPRISES_SEVERAL_AREAS_AND_THE_NATION                               = 7422,  -- Each region comprises several areas, and the nation that rids those areas of the most monsters gains control of the region.
        NATIONS_RECEIVE_GOODS_AND_RESOURCES_FROM_REGIONS_UNDER                           = 7423,  -- Nations receive goods and resources from regions under their control.
        SO_THE_MORE_REGIONS_WE_CONTROL_THE_RICHER                                        = 7424,  -- So, the more regions we control, the richer our nation becomes.
        BORDER_GUARDS_ARE_ALSO_PLACED_IN_OUTPOSTS_WITHIN                                 = 7425,  -- Border guards are also placed in outposts within regions under our control. They are there to cast Signet on adventurers like yourself.
        ONCE_YOU_HAVE_YOUR_NATION_S_SIGNET_YOU                                           = 7426,  -- Once you have your nation's Signet, you will be able to acquire crystals from enemies you defeat.
        NOT_ONLY_THAT_BUT_YOU_WILL_ALSO_RECEIVE                                          = 7427,  -- Not only that, but you will also receive conquest points. You get more conquest points if you defeat enemies in regions that are not under your nation's control. These points can be used to purchase items from guards like myself.
        SO_YOU_SEE_CONQUESTS_BENEFIT_NATIONS_AND_ADVENTURERS                             = 7428,  -- So you see...conquests benefit nations and adventurers alike. We expect you to do your best to serve your country.
        YOU_CAN_SEE_THE_CURRENT_STATE_OF_CONQUESTS                                       = 7429,  -- You can see the current state of conquests by selecting Region Info from the main menu. Conquest results in all regions are regularly recalculated, so you may want to check them from time to time.
        SHOPS_IN_OUR_CITY_WILL_BE_SELLING_DIFFERENT                                      = 7430,  -- Shops in our city will be selling different items according to our conquest rank. The Troupe Valeriano will also visit the nation that finishes first and bring a little joy to its citizens.
        YOU_CAN_DONATE_CRYSTALS_TO_YOUR_NATION_ONCE                                      = 7431,  -- You can donate crystals to your nation once you achieve rank 2. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        WE_WOULD_LIKE_YOU_TO_DONATE_CRYSTALS_TO                                          = 7432,  -- We would like you to donate crystals to your nation from now on. Just trade them to guards like myself, and we will ensure they are sent to the proper place.
        YOU_CAN_ACQUIRE_CRYSTALS_BY_DEFEATING_ENEMIES_WHILE                              = 7433,  -- You can acquire crystals by defeating enemies while you have your nation's Signet. Having Signet cast on you is also the only way of taking part in conquests.
        RANK_POINTS_WILL_BE_AWARDED_TO_YOU_FOR                                           = 7434,  -- Rank points will be awarded to you for each crystal you donate, and you may be offered new missions as your rank goes up.
        YOU_ALSO_RECEIVE_RANK_POINTS_FOR_COMPLETING_MISSIONS                             = 7435,  -- You also receive rank points for completing missions. Complete missions and take part in conquests to raise your rank and serve your country.
        YOU_ARE_AWARDED_CONQUEST_POINTS_WHEN_YOU_DEFEAT                                  = 7436,  -- You are awarded conquest points when you defeat monsters while you are taking part in conquests. Select "Region Info" from the menu to check your current number of conquest points.
        YOU_CAN_PURCHASE_ITEMS_FROM_GUARDS_LIKE_MYSELF                                   = 7437,  -- You can purchase items from guards like myself with your conquest points, but be warned that the number of points you spend will be subtracted from your current total.
        WHEN_CONQUEST_RESULTS_ARE_ANNOUNCED_YOU_WILL_BE                                  = 7438,  -- When conquest results are announced, you will be told which country controls the region you are in at that time. Sometimes regions may become neutral, or beastmen may even gain control of regions.
        IF_WE_GAIN_CONTROL_OF_A_REGION_BORDER                                            = 7439,  -- If we gain control of a region, border guards will be placed at its outposts to help adventurers like you.
        MERCHANTS_WILL_ALSO_BE_PLACED_THERE_AND_GOODS                                    = 7440,  -- Merchants will also be placed there, and goods from that region will find their way to the local shops here.
        GAINING_CONTROL_OF_REGIONS_IS_THE_BASIC_PRINCIPLE                                = 7441,  -- Gaining control of regions is the basic principle behind conquests. We need each of you to do your best, and bring our nation to the top of the ranks.
        OF_COURSE_SOMETIMES_WE_LOSE_REGIONS_TO_OTHER                                     = 7442,  -- Of course, sometimes we lose regions to other nations...so we must try to take them back before the next conquest results are announced.
        AS_AN_INCENTIVE_WE_WILL_AWARD_YOU_WITH                                           = 7443,  -- As an incentive, we will award you with more conquest points for defeating monsters in those regions.
        BUT_IF_WE_ARE_ALLIED_WITH_ANOTHER_NATION                                         = 7444,  -- But if we are allied with another nation, you will only be awarded the regular rate for defeating monsters in our allies' regions. On the other hand, we will award you with more points for fighting in the top-ranked nation's regions.
        OUR_PARAMOUNT_CONCERN_LIES_IN_THE_BEASTMEN_GAINING                               = 7445,  -- Our paramount concern lies in the beastmen gaining control of our regions. If too many of us are defeated in a region, the beastmen will gain control of it.
        IF_THIS_HAPPENS_NOT_ONLY_IS_IT_A                                                 = 7446,  -- If this happens, not only is it a great blow to our pride, but you will be unable to acquire any crystals in that region.
        THE_BEASTMEN_ARE_A_MENACE_TO_ALL_NATIONS                                         = 7447,  -- The beastmen are a menace to all nations. If they rise to power, we must all unite and drive those vile creatures from that region.
        WE_NEED_YOU_TO_BRING_SUPPLIES_TO_THE                                             = 7448,  -- We need you to bring supplies to the outpost border guards who are placed in regions under our control.
        THERE_IS_ONE_OUTPOST_IN_EACH_REGION_SELECT                                       = 7449,  -- There is one outpost in each region. Select Region Info from the menu, and look for the areas with a small flag mark on the map. That is where they are.
        HERE_ARE_THE_SUPPLIES_JUST_GIVE_THEM_TO                                          = 7450,  -- Here are the supplies. Just give them to the guard at the outpost and your mission will be complete. Now, choose which outpost you want to go to. We give different rewards for each region, so choose carefully.
