        WHICH_E_F_WOULD_YOU_LIKE_TO_JOIN                                                 = 7452,  -- Which E.F. would you like to join? . . . . . . The Zulkheim Region (Lv.20`). The Norvallen Region (Lv.25`). . The Derfland Region (Lv.25`). . The Kolshushu Region (Lv.20`). The Aragoneu Region (Lv.25`). The Fauregandi Region (Lv.35`). The Valdeaunia Region (Lv.40`). The Qufim Region (Lv.25`). The Li'Telor Region (Lv.35`). The Kuzotz Region (Lv.40`). The Vollbow Region (Lv.65`). The Elshimo Lowlands Region (Lv.35`). The Elshimo Uplands Region (Lv.45`). . . . . . . . . . . None.
