        I_AM_SORRY_WE_SEEM_TO_HAVE_A                                                     = 7456,  -- I am sorry. We seem to have a problem. Let me cancel it.
        YOU_DO_NOT_NEED_TO_DONATE_ANY_MORE                                               = 7457,  -- You do not need to donate any more crystals at your current rank. Speak to the guard at the gatehouse for further instructions.
