        I_SEE_THAT_YOUR_HOME_COUNTRY_IS_ALLIES                                           = 7491,  -- I see that your home country is allies with the country in control of this region. Feel free to browse through my wares.
        I_CAN_TELEPORT_YOU_TO_YOUR_HOME_COUNTRY                                          = 7492,  -- I can teleport you to your home country for # gil or # conquest [point/points].
        WORD_HAS_IT_THAT_THE_ENTIRE_SET_OF                                               = 7493,  -- Word has it that the entire set of mog tablets has been recovered. Oh, happy day! In honor of the occasion, I can teleport you to your home country free of charge.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS                                              = 7494,  -- I am terribly sorry, but it seems as if you do not have enough gil.
        I_AM_TERRIBLY_SORRY_BUT_IT_SEEMS_AS_2                                            = 7495,  -- I am terribly sorry, but it seems as if you do not have enough conquest points.
