        MATCH_ENTRY_PERIOD_BEGINS_BRIEFING_BEGINS                                        = 7847,  -- <Match #> Entry period begins: Briefing begins:
        I_APOLOGIZE_BUT_YOUR_LEVEL_IS_TOO_LOW                                            = 7848,  -- I apologize, but your level is too low to participate in an official Brenner match.
        OFFICIAL_MATCHES_ARE_SCHEDULED_TO_BEGIN_AT_THE                                   = 7849,  -- Official matches are scheduled to begin at the following times: Match 1: Match 2: Match 3:
        TELEPORTATION_TO_THE_ISLE_IS_FREE_OF_CHARGE                                      = 7850,  -- Teleportation to the Isle is free of charge, but a participation fee of # gil is required before each match.
        TRAVEL_TO_THE_ISLE_YES_NOT_YET                                                   = 7851,  -- Travel to the Isle? Yes. Not yet.
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_BASIC                                          = 7852,  -- What would you like to know about? Basic rules. Official/private matches. Flammen-Brenner. Flamme. Match score. Petras and quarrying. Sprint. KO. Return.
        THE_BASIC_RULES_OF_BRENNER_ARE_AS_FOLLOWS                                        = 7853,  -- The basic rules of Brenner are as follows:
        FIRST_THE_PARTICIPANTS_DIVIDE_INTO_TWO_TEAMS_EACH                                = 7854,  -- First, the participants divide into two teams. Each side's camp contains the same number of Flammen-Brenner.
        AT_THE_BEGINNING_OF_THE_MATCH_HALF_OF                                            = 7855,  -- At the beginning of the match, half of each side's Flammen-Brenner will be ablaze with Flamme, or flame, while the other half will remain unlit.
        PARTICIPANTS_CAN_SEIZE_A_FLAMME_FROM_THE_OPPOSING                                = 7856,  -- Participants can seize a Flamme from the opposing side's Flammen-Brenner and carry it around the Isle.
        THE_GOAL_IS_TO_STEAL_YOUR_OPPONENT_S                                             = 7857,  -- The goal is to steal your opponent's Flamme and use them to light your side's Flammen-Brenner.
        THE_SIDE_THAT_SUCCEEDS_IN_LIGHTING_ALL_OF                                        = 7858,  -- The side that succeeds in lighting all of its Flammen-Brenner will be declared the winner after a specified amount of time.
        IF_NEITHER_SIDE_IS_VICTORIOUS_BEFORE_THE_MATCH                                   = 7859,  -- If neither side is victorious before the match ends, the outcome will be judged based on the score. The match score section of the rulebook contains more information on this subject.
        BRENNER_IS_SIGNIFICANTLY_DIVIDED_INTO_PUBLIC_AND_PRIVATE                         = 7860,  -- Brenner is significantly divided into public and private matches. Official matches are held periodically according to level and feature general participation.
        YOU_CANNOT_RESERVE_THE_ISLE_WHEN_AN_OFFICIAL                                     = 7861,  -- You cannot reserve the Isle when an official match is being held.
        NO_ITEMS_ARE_NECESSARY_FOR_PARTICIPATION_BUT_A                                   = 7862,  -- No items are necessary for participation, but a minor fee will be collected. You will be unable to participate if your level is too low.
        THE_MATCH_OUTCOME_WILL_BE_RECORDED_UNLESS_THE                                    = 7863,  -- The match outcome will be recorded unless the number of participants fails to exceed # members, or if there are fewer than # members in a match where the two sides' numbers differ. In such cases, the game will be considered a training match and will not be recorded.
        PRIVATE_MATCHES_REQUIRE_A_RESERVATION_AND_PARTICIPATION_MAY                      = 7864,  -- Private matches require a reservation, and participation may be limited. The Master of Ceremonies (MC) can freely adjust the rules and control match proceedings.
        LS_LIGA_IS_A_FORM_OF_PRIVATE_MATCH                                               = 7865,  -- LS Liga is a form of private match. You can learn more about LS Liga by speaking to a Marshal.
        A_FLAMMEN_BRENNER_IS_A_DEVICE_THAT_CONTAINS                                      = 7866,  -- A Flammen-Brenner is a device that contains a Flamme (flame). The Flammen-Brenner is covered by a grate that will open after taking a set amount of damage, exposing the Flamme.
        THE_PARTICIPANTS_MUST_UTILIZE_THIS_CHANCE_TO_SEIZE                               = 7867,  -- The participants must utilize this chance to seize the Flamme before the grate recloses. Once the grate is closed, the Flammen-Brenner will begin recovering from the damage it has been dealt.
        IF_YOU_MANAGE_TO_OPEN_THE_OPPOSING_TEAM                                          = 7868,  -- If you manage to open the opposing team's Flammen-Brenner and capture their Flamme, you should make haste to light one of the Flammen-Brenner on your side.
        AFTER_A_CERTAIN_AMOUNT_OF_TIME_THE_FLAMME                                        = 7869,  -- After a certain amount of time, the Flamme will burn out and the opposing team's Flammen-Brenner will be relit.
        ALSO_PLEASE_NOTE_THAT_YOU_CANNOT_QUICKEN_YOUR                                    = 7870,  -- Also, please note that you cannot quicken your pace using any special abilities while you are in possession of a Flamme.
        IN_THE_EVENT_THAT_NEITHER_SIDE_FULFILLS_THE                                      = 7871,  -- In the event that neither side fulfills the conditions for victory, the outcome of the match will be evaluated based on score.
        TEN_POINTS_ARE_AWARDED_TO_EACH_SIDE_FOR                                          = 7872,  -- Ten points are awarded to each side for every lit Flammen-Brenner, while one point is awarded whenever a Flamme is captured, used to light a Flammen-Brenner, or recaptured from an opponent. One point is also awarded for protecting the Flammen-Brenner for a certain period of time.
        LIKE_BALLISTA_QUARRY_QUARRY_CAN_BE_USED_WHILE                                    = 7873,  -- Like Ballista, quarry (/quarry) can be used while playing Brenner. Participants may use this ability to dig up Petras and temporary items.
        HOWEVER_UNLIKE_BALLISTA_PETRAS_BRENNER_PETRAS_HAVE_NO                            = 7874,  -- However, unlike Ballista Petras, Brenner Petras have no effect on the match score. You can trade a Petra to a Pursuivant to recover your HP and MP at no expense to TP.
        SPRINT_CANNOT_BE_USED_WHILE_CARRYING_A_PETRA                                     = 7875,  -- Sprint cannot be used while carrying a Petra. Also, please note that the scout ability cannot be used in Brenner.
        PETRAS_WILL_BE_LOST_IN_THE_EVENT_OF                                              = 7876,  -- Petras will be lost in the event of a KO, but can be carried over from one match to another.
        THE_SPRINT_SPRINT_ABILITY_CAN_BE_USED_TO                                         = 7877,  -- The sprint (/sprint) ability can be used to increase the player's speed when not in possession of a Flamme or Petras.
        IN_THE_EVENT_OF_A_KO_YOU_WILL                                                    = 7878,  -- In the event of a KO, you will be returned to your team's camp. However, recovery will take longer the more often you fall in battle.
        IN_OTHER_WORDS_YOU_WILL_RECEIVE_A_PENALTY                                        = 7879,  -- In other words, you will receive a penalty if you fall immediately after recovering from KO. In addition, your TP will be reduced to zero and you will lose any Petras in your possession.
        I_M_SORRY_I_WASN_T_LISTENING_COULD                                               = 7880,  -- I'm sorry. I wasn't listening. Could you start over from the beginning?
