        I_CAN_SELL_YOU_A_SPLENDID_ENTRY_LEVEL                                            = 8392,  -- I can sell you a splendid entry-level model for # gil. A small price to pay to embark on a lifelong journey of scientific discovery, wouldn't you say?
        GIL_PAID_IN_FULL                                                                 = 8393,  -- # gil, paid in full!
