        I_M_NOT_ONE_FER_BEATIN_ROUND_THE                                                 = 8416,  -- I'm not one fer beatin' 'round the bush, so I'll say it straight. What ye witnessed was a phenomenon called noise--the irregular brushin' of one dimension against another. Ordinary folk don't see such things, mind ye. So I s'pose that makes ye extra-ordinary.
        ME_THEORY_S_THAT_YE_VE_GOT_A                                                     = 8417,  -- Me theory's that ye've got a natural attunement t' the phasic alignment of our dimensions. That be the potential I spoke of when I found ye sprawled on the ground.
        ID_8418                                                                          = 8418,  -- ...
