        I_D_LOVE_NOTHIN_MORE_THAN_TO_SAY                                                 = 8420,  -- I'd love nothin' more than to say this is jus' some hearth tale, I would. We'd all be happier that way, t' be sure. But what's an adventurer if he/she] turns his/her] back t' reality?
        NOW_THIS_ISN_T_T_SAY_THAT_I                                                      = 8421,  -- Now, this isn't t' say that I take ye fer a faithless type, but I've got a feelin' that simple words won't do. Some things a man/woman]'s jus' got t' see with his/her] own two eyes.
        SO_I_WANT_YE_TO_HAVE_THIS                                                        = 8422,  -- So I want ye to have this.
        IT_S                                                                             = 8423,  -- It's %.
        IF_YE_VE_TRULY_GOT_THE_POTENTIAL_I                                               = 8424,  -- If ye've truly got the potential I marked ye fer, that stone there'll guide ye on yer way. Take it with ye an' pay a visit t' one of them cavernous maws.
        YE_KNOW_OF_THOSE_GHASTLY_THINGS_AYE                                              = 8425,  -- Ye know of those ghastly things, aye?
