        WHAT_WOULD_LIKE_TO_ASK_ABOUT_I_WANT                                              = 8460,  -- What would like to ask about? I want %. Learn about %. Current % stock. Cavernous maw locations. Teleporting to a cavernous maw. Nothing right now.
        NOTHIN_YE_NEED_YE_JUS_LET_JOACHIM_HERE                                           = 8461,  -- Nothin' ye need? Ye jus' let Joachim here know if ever ye need more %, aye?
        THE_MAWS_TICKLE_YER_FANCY_EH_2                                                   = 8462,  -- The maws tickle yer fancy, eh?
        MAKE_SURE_YE_VE_GOT_ENOUGH_B_FORE                                                = 8463,  -- Make sure ye've got enough % b'fore ye go divin' into maws.
        AREN_T_JUS_KEYS_T_OPEN_THE_PORTAL                                                = 8464,  -- % aren't jus' keys t' open the portal t' Abyssea.
        THEY_ALSO_SERVE_AS_ANCHORS_WHAT_SECURE_YER                                       = 8465,  -- They also serve as anchors what secure yer essence t' foreign dimensions.
