        OBTAINED_KEY_ITEM_3                                                              = 8481,  -- Obtained key item: # %!
        I_VE_BEEN_TOLD_YE_MET_SOME_MATES                                                 = 8482,  -- %. I've been told ye met some mates of mine.
        YE_OUGHT_T_KNOW_NOW_HOW_STARVED_OF                                               = 8483,  -- Ye ought t' know now how starved of hope me folk are, livin' each day not knowin' if it'd be the last.
        SO_FAR_WE_VE_MANAGED_T_STAY_IN                                                   = 8484,  -- So far we've managed t' stay in the fight, puttin' up protective wards an' pitchin' warmachines into the fray, but they're temporary measures at best.
