        I_BEG_YE_HELP_US_TURN_THE_TIDE                                                   = 8488,  -- I beg ye, %! Help us turn the tide of battle in our favor!
        I_COULDN_T_BELIEVE_ME_EARS_WHEN_FIRST                                            = 8489,  -- %! I couldn't believe me ears when first I heard the news!
        YER_EXPLOITS_AGAINST_THE_ABYSSEAN_HORDES_VE_ALLOWED                              = 8490,  -- Yer exploits against the Abyssean hordes've allowed us t' escape the rut we're in. Fer once I find meself thankin' the gods fer strandin' me in this world.
        WITH_YER_HELP_THERE_S_HOPE_YET_FER                                               = 8491,  -- With yer help, there's hope yet fer Abyssea. Why, there're even some as say it might be restored to its former glory!
        I_MESELF_AM_NOT_ONE_FER_COUNTIN_EGGS                                             = 8492,  -- I meself am not one fer countin' eggs afore they're hatched, but one thing's fer certain:
        THE_SEED_OF_HOPE_HAS_SPROUTED                                                    = 8493,  -- The seed of hope has sprouted!
        A_SEEDLING_IT_IS_STILL_BUT_LIT_WITH                                              = 8494,  -- A seedling it is still, but lit with determination and watered with perseverance, into a great, towerin' oak it'll surely grow!
        A_LONG_ROAD_STRETCHES_FAR_AHEAD_OF_US                                            = 8495,  -- A long road stretches far ahead of us...
        BUT_WITH_YER_HELP_WE_LL_FOLLOW_IT                                                = 8496,  -- But with yer help, %, we'll follow it one step at a time...'til the day we reach its end!
        AH_THERE_YE_ARE_I_WAS_WONDERIN_WHEN                                              = 8497,  -- Ah, there ye are, %. I was wonderin' when next ye'd turn up.
        THERE_BE_SOMETHIN_I_NEED_T_ASK_OF                                                = 8498,  -- There be somethin' I need t' ask of ye. Well, t' be precise, there be someone I'd like ye t' meet.
        DUE_T_REASONS_BEYOND_OUR_CONTROL_THE_MAN                                         = 8499,  -- Due t' reasons beyond our control, the man can't be here. So instead he'll be waitin' for ye at the stone circle in the La Theine Plateau. I trust a veteran adventurer such as yerself knows how t' navigate himself/herself] there.
        TRULY_SORRY_FER_THIS_SUDDEN_REQUEST_BUT_CIRCUMSTANCES                            = 8500,  -- Truly sorry fer this sudden request, but circumstances won't allow fer a meetin' t' take place here. I'd explain the reason why, except I'm sworn t' silence on this.
        GO_MEET_THE_MYSTERY_MAN_OOOH_I_LOVE                                              = 8501,  -- Go meet the mystery man? Oooh, I love mysteries! Sounds a little shady...
        I_BEG_FER_YER_UNDERSTANDIN_YE_KNOW_I                                             = 8502,  -- I beg fer yer understandin', %. Ye know I'd tell ye all if I could, but this is jus' the way it's gotta be.
        I_M_IN_YER_DEBT_YET_AGAIN_NOW                                                    = 8503,  -- I'm in yer debt yet again, %. Now, as I said, ye'll meet yer man at the stone circle in La Theine. Thing is, due t' the stones' properties, he can't be there fer long stretches of time.
