        HM_I_COULD_HAVE_SWORN_THAT_INSCRUTABLE_AURA                                      = 8823,  -- Hm, I could have sworn that inscrutable aura was emanating from you, but I suppose I was mistaken. Feel free to exit my line of sight at any time, plebeian.
        WHAT_CURIOUS_ORDNANCE_YOU_CARRY_MY_HAIRS_ARE                                     = 8824,  -- What curious ordnance you carry. My hairs are standing on end just from being in its proximity.
